SELECT e.*, d.name AS department_name FROM employees e LEFT JOIN departments d ON e.department_id = d.id
AND (e.name LIKE CONCAT('%', #{search}, '%') OR e.email LIKE CONCAT('%', #{search}, '%') OR e.position LIKE CONCAT('%', #{search}, '%'))
AND e.department_id = #{departmentId}
ORDER BY e.id DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*) FROM employees e
AND (e.name LIKE CONCAT('%', #{search}, '%') OR e.email LIKE CONCAT('%', #{search}, '%') OR e.position LIKE CONCAT('%', #{search}, '%'))
AND e.department_id = #{departmentId}
